# Gunicorn configuration for {{ app_label }}
# Generated by Velour App Factory. Regenerate with:
#   python manage.py generate_deploy --target <dir> --project {{ project_name }} --user {{ deploy_user }}

bind = 'unix:/var/www/webapps/{{ deploy_user }}/run/{{ deploy_user }}.sock'
workers = 3
user = '{{ deploy_user }}'
group = '{{ deploy_user }}'
errorlog = '/var/www/webapps/{{ deploy_user }}/log/gunicorn-error.log'
accesslog = '/var/www/webapps/{{ deploy_user }}/log/gunicorn-access.log'
loglevel = 'info'
